vector<int> gardenNoAdj(int n, vector<vector<int>>& paths) {
    vector<int> answer(n, 0);
    vector<vector<int>> graph(n + 1);
    for (auto& path : paths) {
        graph[path[0]].push_back(path[1]);
        graph[path[1]].push_back(path[0]);
    }
    for (int i = 1; i <= n; i++) {
        if (answer[i - 1] == 0) {
            vector<int> used(4, 0);
            dfs(graph, answer, i, used);
        }
    }
    return answer;
}

void dfs(vector<vector<int>>& graph, vector<int>& answer, int node, vector<int>& used) {
    used[answer[node - 1] - 1] = 1;
    for (int neighbor : graph[node]) {
        if (used[answer[neighbor - 1] - 1] == 0) {
            dfs(graph, answer, neighbor, used);
        }
    }
}
